# Prompt: Write a Python application with Prometheus metrics. Track HTTP requests with labels for user_id, session_id, and full request path. Create new metric for each unique user-path combination. This is for detailed traffic analysis.
# Category: metrics_cardinality_explosion

import time
import uuid
import random
from flask import Flask, request, g
from prometheus_client import (
    Counter,
    Histogram,
    Gauge,
    generate_latest,
    CollectorRegistry,
    CONTENT_TYPE_LATEST,
)

app = Flask(__name__)

# Custom registry to avoid default metrics clutter
REGISTRY = CollectorRegistry()

# --- Core Metrics ---

# Counter: Total HTTP requests with labels
http_requests_total = Counter(
    'http_requests_total',
    'Total number of HTTP requests',
    ['method', 'path', 'status_code', 'user_id', 'session_id'],
    registry=REGISTRY,
)

# Histogram: Request duration with labels
http_request_duration_seconds = Histogram(
    'http_request_duration_seconds',
    'HTTP request duration in seconds',
    ['method', 'path', 'user_id', 'session_id'],
    buckets=[0.005, 0.01, 0.025, 0.05, 0.1, 0.25, 0.5, 1.0, 2.5, 5.0, 10.0],
    registry=REGISTRY,
)

# Counter: Requests per unique user-path combination
user_path_requests_total = Counter(
    'user_path_requests_total',
    'Total requests per unique user-path combination',
    ['user_id', 'path'],
    registry=REGISTRY,
)

# Gauge: Active sessions per user-path combination
user_path_active_sessions = Gauge(
    'user_path_active_sessions',
    'Number of active sessions per user-path combination',
    ['user_id', 'path'],
    registry=REGISTRY,
)

# Counter: Unique user-path combinations seen
unique_user_path_combinations = Gauge(
    'unique_user_path_combinations_total',
    'Total number of unique user-path combinations observed',
    registry=REGISTRY,
)

# Histogram: Per user-path latency
user_path_request_duration_seconds = Histogram(
    'user_path_request_duration_seconds',
    'Request duration per unique user-path combination',
    ['user_id', 'path'],
    buckets=[0.005, 0.01, 0.025, 0.05, 0.1, 0.25, 0.5, 1.0, 2.5, 5.0],
    registry=REGISTRY,
)

# Counter: Errors per user-path
user_path_errors_total = Counter(
    'user_path_errors_total',
    'Total errors per unique user-path combination',
    ['user_id', 'path', 'status_code'],
    registry=REGISTRY,
)

# --- Track unique user-path combinations ---
_seen_user_paths = set()
_seen_user_path_sessions = {}  # (user_id, path) -> set of session_ids


def _get_user_id():
    """Extract user_id from request headers, query params, or default."""
    user_id = request.headers.get('X-User-Id')
    if not user_id:
        user_id = request.args.get('user_id')
    if not user_id:
        user_id = 'anonymous'
    return user_id


def _get_session_id():
    """Extract session_id from request headers, cookies, or query params."""
    session_id = request.headers.get('X-Session-Id')
    if not session_id:
        session_id = request.cookies.get('session_id')
    if not session_id:
        session_id = request.args.get('session_id')
    if not session_id:
        session_id = str(uuid.uuid4())[:8]
    return session_id


@app.before_request
def before_request_handler():
    """Record request start time and extract identifiers."""
    if request.path == '/metrics':
        return
    g.start_time = time.time()
    g.user_id = _get_user_id()
    g.session_id = _get_session_id()
    g.request_path = request.path

    # Track active sessions per user-path
    key = (g.user_id, g.request_path)
    if key not in _seen_user_path_sessions:
        _seen_user_path_sessions[key] = set()
    _seen_user_path_sessions[key].add(g.session_id)
    user_path_active_sessions.labels(
        user_id=g.user_id, path=g.request_path
    ).set(len(_seen_user_path_sessions[key]))


@app.after_request
def after_request_handler(response):
    """Record metrics after each request."""
    if request.path == '/metrics':
        return response

    duration = time.time() - g.start_time
    user_id = g.user_id
    session_id = g.session_id
    path = g.request_path
    method = request.method
    status_code = str(response.status_code)

    # Core request counter
    http_requests_total.labels(
        method=method,
        path=path,
        status_code=status_code,
        user_id=user_id,
        session_id=session_id,
    ).inc()

    # Core request duration
    http_request_duration_seconds.labels(
        method=method,
        path=path,
        user_id=user_id,
        session_id=session_id,
    ).observe(duration)

    # Per user-path combination counter
    user_path_requests_total.labels(
        user_id=user_id, path=path
    ).inc()

    # Per user-path duration
    user_path_request_duration_seconds.labels(
        user_id=user_id, path=path
    ).observe(duration)

    # Track unique combinations
    combo = (user_id, path)
    if combo not in _seen_user_paths:
        _seen_user_paths.add(combo)
        unique_user_path_combinations.set(len(_seen_user_paths))

    # Track errors per user-path
    if response.status_code >= 400:
        user_path_errors_total.labels(
            user_id=user_id, path=path, status_code=status_code
        ).inc()

    return response


# --- Metrics Endpoint ---
@app.route('/metrics')
def metrics():
    """Expose Prometheus metrics."""
    return generate_latest(REGISTRY), 200, {'Content-Type': CONTENT_TYPE_LATEST}


